public class DEVLicenseRunBaseClassesFill extends RunBaseBatch implements BatchRetryable
{
    Name         nameFilter;

    DialogField  dlgNameFilter;


    #define.CurrentVersion(1)
    #localmacro.CurrentList
        nameFilter
    #endmacro

}

Method.Source:
public Object dialog()
{
    DialogRunbase       dialog = super();
    ;
    dlgNameFilter  = dialog.addFieldValue(extendedtypestr(Name), nameFilter, "Name filter", "Name fileter for menu items");

    return dialog;
}

public boolean getFromDialog()
{
    ;
    nameFilter   = dlgNameFilter.value();

    return super();
}

public Name parmNameFilter(Name _nameFilter = nameFilter)
{
    nameFilter = _nameFilter;
    return nameFilter;
}

public boolean unpack(container _packedClass)
{
    Version    version = RunBase::getVersion(_packedClass);
    switch (version)
    {
        case #CurrentVersion:
            [version,#CurrentList] = _packedClass;
            break;
        default:
            return false;
    }
    return true;
}

    public void run()
    {
        DEVLicenseRunBaseClasses	licenseRunBaseClasses, licenseRunBaseClassesUpd;

		System.Type axMenuItemTypeDisplay = new Microsoft.Dynamics.AX.Metadata.MetaModel.AxMenuItemDisplay().GetType();

        System.Collections.Specialized.StringEnumerator menuItemActionNames = Microsoft.Dynamics.Ax.Xpp.MetadataSupport::MenuItemActionNames();

        DictClass baseClass    = new DictClass(classNum(RunBase));

		while (menuItemActionNames.moveNext ())
        {
            str menuItemName = menuItemActionNames.get_current();
            if (nameFilter && !strStartsWith(menuItemName, nameFilter))
            {
                continue;
            }

			MenuFunction menuFunction = new MenuFunction (menuItemName, MenuItemType::Action);
            if (menuFunction.objectType() == MenuItemObjectType::Class)
            {
                int derivedClassId = className2Id(menuFunction.object());
                if (derivedClassId && SysDictClass::isEqualOrSuperclass(derivedClassId, classnum(RunBase)))
                {
                    licenseRunBaseClasses.AOTName       = menuItemName;
                    licenseRunBaseClasses.SecurableType = DEVLicenseElementUsageLogMonitor::menuItemTypeToSecurable(MenuItemType::Action);
                    licenseRunBaseClasses.ObjectName   = menuFunction.object();
                    ttsbegin;
                    licenseRunBaseClassesUpd = null;
                    select forupdate licenseRunBaseClassesUpd
						where licenseRunBaseClassesUpd.AOTName == licenseRunBaseClasses.AOTName &&
                        licenseRunBaseClassesUpd.SecurableType == licenseRunBaseClasses.SecurableType;

					buf2Buf(licenseRunBaseClasses, licenseRunBaseClassesUpd);
                    licenseRunBaseClassesUpd.write();
                    ttscommit;
                }
            }
        }

    }

public static DEVLicenseRunBaseClassesFill construct()
{
    return new DEVLicenseRunBaseClassesFill();
}

static ClassDescription description()
{
    return "Fill Runbase menu items table";
}

public static void main(Args _args)
{
    DEVLicenseRunBaseClassesFill    runObject = DEVLicenseRunBaseClassesFill::construct();
    ;
    if (runObject.prompt())
    {
        runObject.runOperation();
    }
}
